# ============================================================
#  P2-3 多笔合并工具
# ============================================================

def merge_positions_data(positions_list):
    """将多笔同 code 持仓合并为一笔（cost 加权、shares 累加）。

    参数:
        positions_list: [{'code': str, 'cost': float, 'can_use': int, 'volume': int}, ...]

    返回:
        {'code': {'cost': float, 'can_use': int, 'volume': int}}
    """
    merged = {}
    for pos in positions_list:
        code = pos.get('code', '')
        if not code:
            continue
        cost = pos.get('cost', 0)
        can_use = pos.get('can_use', 0)
        volume = pos.get('volume', 0)
        if code not in merged:
            merged[code] = {'cost': cost, 'can_use': can_use, 'volume': volume}
        else:
            old = merged[code]
            total_vol = old['volume'] + volume
            if total_vol > 0 and old['volume'] > 0 and volume > 0:
                old['cost'] = (old['cost'] * old['volume'] + cost * volume) / total_vol
            elif volume > 0:
                old['cost'] = cost
            old['volume'] = total_vol
            old['can_use'] = old['can_use'] + can_use
    return merged


# ============================================================
#  数据类型
# ============================================================

class Action(Enum):
    HOLD = "持有"
    REDUCE = "减仓"
    CLEAR = "清仓"


class SellDecision:
    """分层决策结果"""
    def __init__(self, action=Action.HOLD, code='', sell_pct=0.0, reason='',
                 triggered_layer='', triggered_signals=None, triggered_sublayer=None):
        self.action = action
        self.code = code
        self.sell_pct = sell_pct
        self.reason = reason
        self.triggered_layer = triggered_layer
        self.triggered_signals = triggered_signals if triggered_signals is not None else []
        self.triggered_sublayer = triggered_sublayer

    @staticmethod
    def hold():
        return SellDecision()

    @staticmethod
    def reduce(code, pct, reason, layer, signals=None):
        return SellDecision(Action.REDUCE, code, pct, reason, layer, signals or [])

    @staticmethod
    def clear(code, reason, layer, signals=None, sublayer=None):
        return SellDecision(Action.CLEAR, code, 1.0, reason, layer, signals or [], triggered_sublayer=sublayer)


class SellPositionState:
    """每只持仓的卖出状态机。"""
    def __init__(self, code='', cost_price=0.0, current_shares=0, original_shares=0,
                 highest_price=0.0, entry_date='',
                 warning_reduced=False, warning_trigger_date='', warning_reason='',
                 b1_needs_nextday_check=False, b1_trigger_date='', b1_additional_reduced=False,
                 confirm_reduced=False, confirm_trigger_date='', confirm_reason='',
                 cleared=False, cleared_date='',
                 rebound_restored=False, reduction_volume=0,
                 quality='', hard_stop_loss=None,
                 source_tag='', float_pnl_pct=0.0,
                 buy_logic_type='', buy_reason_tags=None, max_profit_since_buy=0.0):
        self.code = code
        self.cost_price = cost_price
        self.current_shares = current_shares
        self.original_shares = original_shares
        self.highest_price = highest_price
        self.entry_date = entry_date
        self.warning_reduced = warning_reduced
        self.warning_trigger_date = warning_trigger_date
        self.warning_reason = warning_reason
        self.b1_needs_nextday_check = b1_needs_nextday_check
        self.b1_trigger_date = b1_trigger_date
        self.b1_additional_reduced = b1_additional_reduced
        self.confirm_reduced = confirm_reduced
        self.confirm_trigger_date = confirm_trigger_date
        self.confirm_reason = confirm_reason
        self.cleared = cleared
        self.cleared_date = cleared_date
        self.rebound_restored = rebound_restored
        self.reduction_volume = reduction_volume
        self.quality = quality
        self.hard_stop_loss = hard_stop_loss
        self.source_tag = source_tag if source_tag else 'strategy'
        self.float_pnl_pct = float_pnl_pct
        self.buy_logic_type = buy_logic_type
        self.buy_reason_tags = buy_reason_tags if buy_reason_tags is not None else []
        self.max_profit_since_buy = max_profit_since_buy


# ============================================================
#  状态查询（纯函数）
# ============================================================

def get_trade_state_reason(state):
    """将卖出状态转为可读的原因字符串。"""
    if state is None:
        return "无状态"
    if state.cleared:
        d = state.cleared_date or "?"
        return "已清仓(%s)" % d
    if state.confirm_reduced:
        return "确认层减仓(%s)" % (state.confirm_reason or '无')
    if state.warning_reduced:
        return "预警层减仓(%s)" % (state.warning_reason or '无')
    if state.b1_needs_nextday_check:
        return "B1放量预警(待隔日确认)"
    return "持有中"


# ============================================================
#  分层卖出决策引擎
# ============================================================

class SellStrategyEngine:
    """
    分层卖出决策引擎。
    只做条件判断，返回 SellDecision。不调 passorder。
    交易执行由 adapter 层负责。
    """

    def __init__(self, strategy_name, account_id,
                 state_file, is_intraday=True,
                 hard_stop_loss=BOTTOM_LINE_LOSS_PCT,
                 judge_entry_quality=True,
                 enable_profit_tiered_stop=None,
                 enable_three_phase_trailing=None,
                 enable_event_gate=None,
                 enable_strategy_exit=None,
                 strategy_adapter=None,
                 daily_max_loss_pct=-0.03):
        """
        参数:
            strategy_name: 策略名称
            account_id: QMT 账号
            state_file: 状态持久化文件路径
            is_intraday: True=盘中, False=尾盘
            hard_stop_loss: 硬止损阈值 (默认 -5%)
            judge_entry_quality: 入场接管开关 (默认 True, False 时禁用质量档)
            enable_profit_tiered_stop: 浮盈分层止损开关 (默认 None=读模块常量)
            enable_three_phase_trailing: 三阶段移动止盈开关 (默认 None=读模块常量)
            enable_event_gate: 事件门控开关 (默认 None=读模块常量)
            enable_strategy_exit: 策略侧止盈开关 (默认 None=读模块常量)
            strategy_adapter: StrategyExitAdapter 实例 (默认 None)
            daily_max_loss_pct: 日内最大亏损熔断阈值 (默认 -3%)
        """
        self.strategy_name = strategy_name
        self.account_id = account_id
        self.state_file = state_file
        self.is_intraday = is_intraday
        self.hard_stop_loss = hard_stop_loss
        self.judge_entry_quality = judge_entry_quality

        # 安全开关（None时读模块级默认值，默认OFF=老版本）
        self.enable_profit_tiered_stop = enable_profit_tiered_stop if enable_profit_tiered_stop is not None else ENABLE_PROFIT_TIERED_STOP
        self.enable_three_phase_trailing = enable_three_phase_trailing if enable_three_phase_trailing is not None else ENABLE_THREE_PHASE_TRAILING
        self.enable_event_gate = enable_event_gate if enable_event_gate is not None else ENABLE_EVENT_GATE
        self.enable_strategy_exit = enable_strategy_exit if enable_strategy_exit is not None else ENABLE_STRATEGY_EXIT
        self._strategy_adapter = strategy_adapter

        # 日内熔断
        self._daily_max_loss_pct = daily_max_loss_pct
        self._day_start_nav = 0.0
        self._daily_circuit_breaker = False

        # 大盘环境（evaluate 后更新，is_buy_allowed 可提前调用）
        self._current_regime_mult = 1.0

        # 状态缓存: {code: SellPositionState}
        self._states = {}

    # ================================================================
    #  大盘环境感知
    # ================================================================

    def _judge_market_regime(self, index_df):
        """基于上证指数判断大盘环境：BULL/NEUTRAL/BEAR/CRASH。

        判断逻辑:
          - CRASH: 单日跌幅 > 5%
          - BULL: close > MA20 且 MA20 > MA60
          - BEAR: close < MA20 且 MA20 < MA60
          - NEUTRAL: MA20 ±3% 震荡

        返回: str (REGIME_BULL / REGIME_NEUTRAL / REGIME_BEAR / REGIME_CRASH)
        """
        if index_df is None or len(index_df) < 62:
            return REGIME_NEUTRAL

        close = index_df['close'].astype(float)
        if len(close) < 62:
            return REGIME_NEUTRAL

        current = float(close.iloc[-1])
        prev = float(close.iloc[-2])

        # CRASH: 单日跌 > 5%
        if prev > 0:
            daily_drop = (current - prev) / prev
            if daily_drop < -0.05:
                return REGIME_CRASH

        ma20 = float(close.rolling(20).mean().iloc[-1])
        ma60 = float(close.rolling(60).mean().iloc[-1])

        if ma20 <= 0 or ma60 <= 0:
            return REGIME_NEUTRAL

        # BULL: close > MA20 且 MA20 > MA60
        if current > ma20 and ma20 > ma60:
            return REGIME_BULL

        # BEAR: close < MA20 且 MA20 < MA60
        if current < ma20 and ma20 < ma60:
            return REGIME_BEAR

        return REGIME_NEUTRAL

    def get_regime_trailing_mult(self, regime):
        """返回当前 regime 对应的跟踪止损乘数。"""
        return REGIME_TRAILING_MULT.get(regime, 1.0)

    def get_regime_position_mult(self, regime):
        """返回当前 regime 对应的仓位乘数。"""
        return REGIME_POSITION_MULT.get(regime, 1.0)

    # ================================================================
    #  日内熔断
    # ================================================================

    def set_day_start_nav(self, nav):
        """init/handlebar日切时调用，记录当日开盘净值。"""
        self._day_start_nav = float(nav)
        self._daily_circuit_breaker = False

    def reset_daily_breaker(self):
        """日切重置熔断状态。"""
        self._daily_circuit_breaker = False
        self._day_start_nav = 0.0

    def is_buy_allowed(self, current_asset, capital):
        """综合判断是否允许买入（regime仓位 + 日内熔断）。

        返回:
            (bool, str): (是否允许买入, 原因)
        """
        if self._current_regime_mult == 0:
            return False, "大盘CRASH空仓，禁止买入"
        if self._daily_circuit_breaker:
            return False, "日内熔断，暂停买入"
        if self._day_start_nav > 0 and capital > 0:
            daily_pnl = current_asset - self._day_start_nav
            daily_pnl_pct = daily_pnl / capital
            if daily_pnl_pct <= self._daily_max_loss_pct:
                self._daily_circuit_breaker = True
                print("[熔断] 日内亏损超限额(%.2f%%)，暂停所有买入" % (daily_pnl_pct * 100))
                return False, "日内亏损%.2f%%触发熔断" % (daily_pnl_pct * 100)
        return True, ""

    # ================================================================
    #  公开入口
    # ================================================================

    def _check_event_gate(self, code, stock_name):
        """P1-5 事件门控：检测致命事件（ST/*ST），返回 CLEAR 或 HOLD。

        参数:
            code: 股票代码
            stock_name: 股票名称（由 adapter 层从 QMT API 获取）

        返回:
            SellDecision: CLEAR（ST/*ST）或 HOLD（正常）
        """
        if stock_name and 'ST' in stock_name.upper():
            return SellDecision.clear(
                code, "P0致命事件:%s检测到ST" % stock_name, "事件门控",
                ["ST检测:%s" % stock_name]
            )
        return SellDecision.hold()

    def evaluate(self, today, holdings_dict, all_data, positions_data=None, rt_prices=None, market_regime=None, stock_names=None):
        """
        主入口：执行分层卖出检查，返回决策列表。

        参数:
            today: YYYYMMDD
            holdings_dict: {code: highest_price} 向后兼容参数（引擎已不依赖其 highest，由 state 自维护）
            all_data: {code: DataFrame} 行情数据
            positions_data: {code: {'cost': float, 'can_use': int, 'volume': int, 'source_tag': str}}
                            QMT 持仓数据（由 adapter 层传入）
            rt_prices: {code: float} 盘中实时价格，用于底线层计算
            market_regime: str or None. 大盘环境标签 (BULL/NEUTRAL/BEAR/CRASH)。
                           None 时默认 NEUTRAL（兼容旧调用方）。
            stock_names: dict {code: name} or None. P1-5 股票名称映射（实盘用）。
                         None 时跳过事件门控层（兼容回测）。

        返回: [(code, SellDecision, shares_to_sell), ...]
        """
        if market_regime is None:
            market_regime = REGIME_NEUTRAL
        self._current_regime = market_regime
        self._current_regime_mult = REGIME_TRAILING_MULT.get(market_regime, 1.0)
        if positions_data is None:
            positions_data = {}
        if rt_prices is None:
            rt_prices = {}

        decisions = []
        if not holdings_dict:
            return decisions

        for code in list(holdings_dict.keys()):
            # ---- P1-5 事件门控（ST检测，最高优先级） ----
            if self.enable_event_gate and stock_names is not None:
                stock_name = stock_names.get(code, '')
                event_decision = self._check_event_gate(code, stock_name)
                if event_decision.action != Action.HOLD:
                    state = self._get_state(code)
                    if state is not None:
                        state.cleared = True
                        state.cleared_date = today
                        state.current_shares = 0
                        self._save_state(code, state)
                    shares_to_sell = positions_data.get(code, {}).get('can_use', 0)
                    decisions.append((code, event_decision, shares_to_sell))
                    continue

            df = all_data.get(code)
            if df is None or len(df) < 30:
                continue

            state = self._get_state(code)
            if state is None:
                if self.judge_entry_quality:
                    quality = self._judge_entry_quality(code, df, today)
                    state = SellPositionState(
                        code=code, entry_date=today,
                        quality=quality,
                        hard_stop_loss=QUALITY_HARD_STOP_MAP.get(quality, self.hard_stop_loss)
                    )
                else:
                    state = SellPositionState(code=code, entry_date=today)

            # ---- P2-5 同步 source_tag（只在首次/未设置时写入，不覆盖手动标签） ----
            pos = positions_data.get(code, {})
            pos_tag = pos.get('source_tag', '')
            if pos_tag and (not state.source_tag or state.source_tag == SOURCE_TAG_DEFAULT):
                state.source_tag = pos_tag

            # ---- 同步外部数据到状态 ----
            close = df['close'].astype(float)
            current_price = float(close.iloc[-1])

            if state.cleared and pos.get('volume', 0) > 0:
                if self.is_reentry_allowed(code, today, df):
                    if self.judge_entry_quality:
                        quality = self._judge_entry_quality(code, df, today)
                        state = SellPositionState(
                            code=code, entry_date=today,
                            quality=quality,
                            hard_stop_loss=QUALITY_HARD_STOP_MAP.get(quality, self.hard_stop_loss),
                            source_tag=pos_tag or state.source_tag
                        )
                    else:
                        state = SellPositionState(code=code, entry_date=today,
                                                  source_tag=pos_tag or state.source_tag)
            cost_price = pos.get('cost', 0)
            if cost_price > 0:
                state.cost_price = cost_price
            state.current_shares = pos.get('can_use', 0)
            if state.original_shares <= 0:
                state.original_shares = state.current_shares

            # 最高价：引擎内部自维护，不依赖外部 holdings_dict 传入
            if state.highest_price <= 0:
                init_price = state.cost_price if state.cost_price > 0 else current_price
                state.highest_price = init_price
            state.highest_price = max(state.highest_price, current_price)

            # ---- 更新 max_profit_since_buy ----
            if state.cost_price > 0:
                today_profit = (current_price - state.cost_price) / state.cost_price
                state.max_profit_since_buy = max(state.max_profit_since_buy, today_profit)

            # ---- P2-4 更新浮盈率 ----
            if state.cost_price > 0:
                state.float_pnl_pct = (current_price - state.cost_price) / state.cost_price

            # ---- P2-5 保守档硬止损覆盖 ----
            tag_stop = self._get_tag_hard_stop(code)
            if tag_stop is not None:
                state.hard_stop_loss = tag_stop

            # ---- 策略侧止盈钩子（优先级最高） ----
            if self.enable_strategy_exit and self._strategy_adapter:
                # 构建 holdings_state 用于策略侧止盈判断
                holdings_state = {
                    code: {
                        'buy_price': state.cost_price,
                        'max_profit_since_buy': getattr(state, 'max_profit_since_buy', 0.0),
                        'current_price': current_price,
                    }
                }
                exit_decision = self._strategy_adapter.check_strategy_exit(
                    code, all_data.get(code, {}), holdings_state
                )
                if exit_decision.action.value != "HOLD":
                    # 转换为 SellDecision
                    if exit_decision.action.value == "SELL":
                        decision = SellDecision.clear(
                            code, "策略侧止盈:%s" % exit_decision.reason, "策略侧止盈"
                        )
                    elif exit_decision.action.value == "REDUCE":
                        decision = SellDecision.reduce(
                            code, exit_decision.pct, "策略侧止盈:%s" % exit_decision.reason, "策略侧止盈"
                        )
                    else:
                        decision = SellDecision.hold()
                    
                    if decision.action != Action.HOLD:
                        shares_to_sell = int(state.original_shares * decision.sell_pct)
                        if shares_to_sell >= 100:
                            shares_to_sell = (shares_to_sell // 100) * 100
                            state.cleared = True
                            state.cleared_date = today
                            state.current_shares = 0
                            self._save_state(code, state)
                            decisions.append((code, decision, shares_to_sell))
                            continue

            # ---- 绝对止损-15%底线（不管策略说什么，跌超15%强制清仓） ----
            if state.cost_price > 0:
                drawdown_since_buy = (current_price - state.cost_price) / state.cost_price
                if drawdown_since_buy < -0.15:
                    decision = SellDecision.clear(
                        code, "绝对止损-15%", "底线层", ["绝对止损-15%"]
                    )
                    shares_to_sell = state.original_shares
                    if shares_to_sell >= 100:
                        shares_to_sell = (shares_to_sell // 100) * 100
                        state.cleared = True
                        state.cleared_date = today
                        state.current_shares = 0
                        self._save_state(code, state)
                        decisions.append((code, decision, shares_to_sell))
                    continue

            # ---- 分层评估 ----
            rt_price = rt_prices.get(code)
            decision = self._evaluate_position(code, df, state, today, rt_price)

            if decision.action != Action.HOLD:
                shares_to_sell = int(state.original_shares * decision.sell_pct)
                if shares_to_sell >= 100:
                    shares_to_sell = (shares_to_sell // 100) * 100
                    if decision.action == Action.REDUCE:
                        if decision.triggered_layer == "预警层":
                            state.warning_reduced = True
                            state.warning_trigger_date = today
                            state.warning_reason = decision.reason
                            state.reduction_volume += shares_to_sell
                        elif decision.triggered_layer == "warning_add":
                            state.b1_additional_reduced = True
                            state.b1_needs_nextday_check = False
                            state.reduction_volume += shares_to_sell
                        elif decision.triggered_layer == "确认层":
                            state.confirm_reduced = True
                            state.confirm_trigger_date = today
                            state.confirm_reason = decision.reason

                self._save_state(code, state)
                decisions.append((code, decision, shares_to_sell))

        return decisions

    def run_end_of_day_sell(self, today, holdings_dict, all_data, positions_data=None, market_regime=None):
        """收盘后补卖。调用 evaluate 完成。"""
        return self.evaluate(today, holdings_dict, all_data, positions_data, market_regime=market_regime)

    # [1b-2] 引擎对外查询接口：买入侧(qmt_wrapper)调用，查询禁入期状态。
    # 设计意图：引擎自管禁入期状态，买入侧可调用但不形成强耦合。
    def is_reentry_allowed(self, code, today, df=None):
        """检查某股票是否允许重新买入（清仓后 NO_REENTRY_DAYS 禁止期）。"""
        state = self._states.get(code)
        if not state or not state.cleared or not state.cleared_date:
            return True

        cleared = datetime.strptime(state.cleared_date, '%Y%m%d')
        today_dt = datetime.strptime(today, '%Y%m%d')
        diff_days = (today_dt - cleared).days

        if df is not None:
            dates = pd.to_datetime(df.index)
            d1 = pd.Timestamp(state.cleared_date)
            d2 = pd.Timestamp(today)
            trading_days = len(dates[(dates > d1) & (dates <= d2)])
            allowed = trading_days >= NO_REENTRY_DAYS
        else:
            allowed = diff_days >= NO_REENTRY_DAYS + 8

        if allowed:
            self._states.pop(code, None)
            self.save_state()
        return allowed

    # ---- P2-4 仓位联动接口 ----
    def is_add_position_allowed(self, code):
        """检查某股票是否允许加仓（浮亏>10%禁止加仓）。

        返回:
            (bool, str): (是否允许加仓, 原因)
        """
        state = self._states.get(code)
        if state is None:
            return True, ''

        if state.cleared:
            return True, ''

        float_pnl = getattr(state, 'float_pnl_pct', 0.0)
        if float_pnl < FLOAT_PNL_ADD_THRESHOLD:
            return False, '浮亏%.1f%%超阈值%.1f%%禁止加仓' % (
                float_pnl * 100, FLOAT_PNL_ADD_THRESHOLD * 100)
        return True, ''

    def _get_tag_tier(self, code):
        """P2-5: 根据 source_tag 返回退出参数档位名。"""
        state = self._states.get(code)
        tag = getattr(state, 'source_tag', SOURCE_TAG_DEFAULT) if state else SOURCE_TAG_DEFAULT
        return TAG_TIER_MAP.get(tag, 'standard')

    def _get_tag_hard_stop(self, code):
        """P2-5: 根据 source_tag 返回对应硬止损阈值。"""
        tier = self._get_tag_tier(code)
        if tier == 'conservative':
            return CONSERVATIVE_HARD_STOP
        return None

    def load_state(self):
        """从文件加载状态。"""
        self._states = {}
        if not os.path.exists(self.state_file):
            return
        try:
            with open(self.state_file, 'r', encoding='utf-8') as f:
                raw = json.load(f)
            for code, data in raw.items():
                known = {k: v for k, v in data.items()
                         if k in SellPositionState.__init__.__code__.co_varnames}
                self._states[code] = SellPositionState(**known)
        except Exception:
            pass

    def save_state(self):
        """持久化状态到文件。"""
        if not self._states:
            return
        try:
            dirname = os.path.dirname(self.state_file)
            if dirname:
                os.makedirs(dirname, exist_ok=True)
            raw = {code: st.__dict__ for code, st in self._states.items()}
            with open(self.state_file, 'w', encoding='utf-8') as f:
                json.dump(raw, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    def _get_state(self, code):
        """获取持仓状态。"""
        return self._states.get(code)

    def _save_state(self, code, state):
        """更新单只持仓状态并持久化。"""
        self._states[code] = state
        self.save_state()

    def confirm_clear(self, code, today):
        """确认清仓成交后更新状态（由集成层回调）。"""
        state = self._get_state(code)
        if state:
            state.cleared = True
            state.cleared_date = today
            state.current_shares = 0
            self._save_state(code, state)

    # ================================================================
    #  反弹决策（仅返回决策，由 adapter 执行）
    # ================================================================

    def check_rebound(self, code, df, state, today):
        """
        检测预警减仓后是否出现反弹修复。
        返回 (should_buy_back, buy_volume, reason) 或 (False, 0, "").
        """
        if not state.warning_reduced or state.rebound_restored:
            return False, 0, ""

        if not state.warning_trigger_date:
            return False, 0, ""

        trigger_dt = datetime.strptime(state.warning_trigger_date, '%Y%m%d')
        today_dt = datetime.strptime(today, '%Y%m%d')
        days_passed = (today_dt - trigger_dt).days

        if days_passed < 1 or days_passed > REBOUND_WINDOW_DAYS:
            if days_passed > REBOUND_WINDOW_DAYS:
                state.rebound_restored = True
            return False, 0, ""

        close = df['close'].astype(float)
        open_ = df['open'].astype(float)
        high = df['high'].astype(float)

        current_price = float(close.iloc[-1])
        current_open = float(open_.iloc[-1])
        ma5 = float(close.rolling(5).mean().iloc[-1])

        if current_price <= ma5:
            return False, 0, ""
        if current_price <= current_open:
            return False, 0, ""

        if len(close) >= 2:
            prev_high = float(high.iloc[-2])
            if current_price <= prev_high:
                return False, 0, ""

        buy_volume = state.reduction_volume
        if buy_volume > 0:
            return True, buy_volume, "反弹修复"
        return False, 0, ""

    def apply_rebound_state(self, code, state):
        """反弹执行后更新状态机（由 adapter 层回调）。"""
        state.rebound_restored = True
        state.warning_reduced = False
        state.warning_trigger_date = ''
        state.warning_reason = ''
        state.b1_needs_nextday_check = False
        state.b1_trigger_date = ''
        state.b1_additional_reduced = False
        state.confirm_reduced = False
        state.confirm_trigger_date = ''
        state.confirm_reason = ''
        state.cleared = False
        state.cleared_date = ''
        state.reduction_volume = 0
        self._save_state(code, state)

    # ================================================================
    #  入场质量判断
    # ================================================================

    def _judge_entry_quality(self, code, df, today):
        """判断入场质量：优质/一般/劣质（基于MA20+趋势）。

        - 优质：close > MA20 且 MA20 上行（趋势向上）-> hard_stop_loss = -8%
        - 一般：close 在 MA20±3% 震荡 -> hard_stop_loss = -6%
        - 劣质：close < MA20（已破位）-> hard_stop_loss = -4%
        """
        close = df['close'].astype(float)
        if len(close) < 22:
            return '一般'

        current_price = float(close.iloc[-1])
        ma20 = close.rolling(20).mean()
        ma20_val = float(ma20.iloc[-1])

        if ma20_val <= 0:
            return '一般'

        deviation = (current_price - ma20_val) / ma20_val

        # MA20 斜率
        angle = calc_angle_simple(ma20)
        ma20_up = angle is not None and angle > 5

        if current_price > ma20_val and ma20_up:
            return '优质'
        elif current_price < ma20_val:
            return '劣质'
        else:
            return '一般'

    # ================================================================
    #  分层决策引擎
    # ================================================================

    def _evaluate_position(self, code, df, state, today, rt_price=None):
        """
        按优先级执行分层评估。
        返回 SellDecision。
        """
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        open_ = df['open'].astype(float)
        volume = df['volume'].astype(float)

        # ① 底线层（最高优先级）
        decision = self._check_bottom_line(close, high, code, state, today, rt_price)
        if decision.action != Action.HOLD:
            return decision

        # ② 如果已清仓，跳过所有检查
        if state.cleared:
            return SellDecision.hold()

        # ③ 清仓层（传入 regime 跟踪止损乘数）
        regime_mult = getattr(self, '_current_regime_mult', 1.0)
        decision = self._check_clear_level(close, high, low, volume, df, state, today, regime_mult)
        if decision.action != Action.HOLD:
            return decision

        # ④ 预警层
        if not state.warning_reduced:
            warning_signals = []
            b1_triggered, b1_reason = self._signal_explosive_volume(close, high, open_, volume)
            if b1_triggered:
                warning_signals.append(b1_reason)
                state.b1_needs_nextday_check = True
                state.b1_trigger_date = today
            if self._signal_volume_divergence(close, volume):
                warning_signals.append("B2:量价背离")
            if self._signal_macd_shortening(close):
                warning_signals.append("C2:MACD红柱缩短")
            if self._signal_kdj_death(close, high, low):
                warning_signals.append("KDJ死叉+MA5走平")

            if warning_signals:
                state.warning_reduced = True
                state.warning_trigger_date = today
                state.warning_reason = " | ".join(warning_signals)
                self._save_state(code, state)
                return SellDecision.reduce(
                    code, WARNING_REDUCE_PCT,
                    " | ".join(warning_signals), "预警层", warning_signals
                )

        # ⑤ 确认层（预警已触发后检查）
        if state.warning_reduced and not state.confirm_reduced:
            if state.b1_needs_nextday_check and not state.b1_additional_reduced:
                b1_decision = self._check_b1_nextday_additional(close, open_, code, state, today)
                if b1_decision.action != Action.HOLD:
                    return b1_decision

            confirm_decision = self._check_confirm_level(close, high, low, open_, volume, df, state, today)
            if confirm_decision.action != Action.HOLD:
                return confirm_decision

        return SellDecision.hold()

    # ================================================================
    #  底线层
    # ================================================================

    def _calc_profit_tier_stop(self, profit_pct, base_stop):
        """P1-2: 根据浮盈区间动态调整止损线。"""
        if profit_pct >= PROFIT_TIER_3:
            return profit_pct * PROFIT_TIER_3_RATIO
        elif profit_pct >= PROFIT_TIER_2:
            return profit_pct * PROFIT_TIER_2_RATIO
        elif profit_pct >= PROFIT_TIER_1:
            return 0.0
        else:
            return base_stop

    def _check_bottom_line(self, close, high, code, state, today, rt_price=None):
        """底线层：硬止损检查（P1-2 浮盈分层版 / 开关OFF=老版本固定止损）"""
        if len(close) < 2:
            return SellDecision.hold()

        if rt_price is not None:
            current_price = rt_price
        else:
            current_price = float(close.iloc[-1])
        prev_close = float(close.iloc[-2])

        signals = []

        if state.cost_price > 0:
            loss_pct = (current_price - state.cost_price) / state.cost_price
            base_stop = state.hard_stop_loss if state.hard_stop_loss is not None else self.hard_stop_loss
            if self.enable_profit_tiered_stop:
                effective_stop = self._calc_profit_tier_stop(loss_pct, base_stop)
            else:
                effective_stop = base_stop
            if loss_pct <= effective_stop:
                signals.append("累计亏损%.1f%%" % (loss_pct * 100))
                return SellDecision.clear(
                    code, "硬止损:累计亏损%.1f%%" % (loss_pct * 100), "底线层", signals
                )

        if prev_close > 0:
            daily_drop = (current_price - prev_close) / prev_close
            if daily_drop <= BOTTOM_LINE_DAILY_DROP_PCT:
                signals.append("单日跌幅%.1f%%" % (daily_drop * 100))
                return SellDecision.clear(
                    code, "硬止损:单日跌幅%.1f%%" % (daily_drop * 100), "底线层", signals
                )

        return SellDecision.hold()

    # ================================================================
    #  预警层
    # ================================================================

    def _check_b1_nextday_additional(self, close, open_, code, state, today):
        if not state.b1_trigger_date or today <= state.b1_trigger_date:
            return SellDecision.hold()
        if self._signal_b1_nextday_unrecovered(close, open_, state):
            return SellDecision.reduce(
                code, WARNING_ADD_REDUCE_PCT,
                "B1次日未修复", "warning_add", ["B1次日未修复"]
            )
        return SellDecision.hold()

    # ================================================================
    #  确认层
    # ================================================================

    def _check_confirm_level(self, close, high, low, open_, volume, df, state, today):
        """检查确认层：3个信号任一个触发 → 再减50%"""
        code = state.code if state.code else ""
        signals = []
        ma10 = close.rolling(10).mean()

        if self._signal_break_ma10(close, ma10):
            signals.append("A2:破10日线")
        if self._signal_high_long_shadow(high, close, open_):
            signals.append("C1:高位长上影")
        if self._signal_high_volume_negative(close, open_, volume):
            signals.append("B3:高位天量收阴")

        if signals:
            return SellDecision.reduce(
                code, CONFIRM_REDUCE_PCT,
                " | ".join(signals), "确认层", signals
            )
        return SellDecision.hold()

    # ================================================================
    #  清仓层
    # ================================================================

    def _check_clear_level(self, close, high, low, volume, df, state, today, regime_mult=1.0):
        """检查清仓层：5种条件任一个触发 → 清仓"""
        code = state.code if state.code else ""
        if not code:
            return SellDecision.hold()

        ma20 = close.rolling(20).mean()
        signals = []

        if self._signal_break_ma20_3days(close, ma20):
            signals.append("A3:破20日线")
        if self._signal_break_highest_low(close, high, low):
            signals.append("C3:破最高日低点")

        # 预警已减仓但确认层尚未处理时，跳过移动止盈让确认层优先决策
        if not (state.warning_reduced and not state.confirm_reduced):
            if self._check_trailing_profit(close, high, low, state, regime_mult):
                signals.append("移动止盈")

        if signals:
            trailing_sublayer = None
            if len(signals) == 1 and signals[0] == "移动止盈":
                trailing_sublayer = 'trailing'
            return SellDecision.clear(
                code, " | ".join(signals), "清仓层", signals, sublayer=trailing_sublayer
            )
        return SellDecision.hold()

    # ================================================================
    #  移动止盈
    # ================================================================

    def _calc_dynamic_drawdown_threshold(self, highest_price, atr):
        """计算动态回撤阈值。

        公式：max(固定下限, N × ATR / 最高价)
        限制：上限 15%

        参数:
            highest_price: 持仓期间最高价
            atr: ATR(14) 值

        返回:
            float: 动态回撤阈值 (0.06 ~ 0.15)
        """
        if highest_price <= 0 or atr <= 0:
            return TRAILING_DRAWDOWN_FLOOR

        atr_pct = TRAILING_ATR_N * atr / highest_price
        dynamic = max(TRAILING_DRAWDOWN_FLOOR, atr_pct)
        return min(dynamic, TRAILING_DRAWDOWN_CAP)

    def _check_trailing_profit(self, close, high, low, state, regime_mult=1.0):
        """检查移动止盈条件。

        开关ON: P2-1 三阶段版（成长期/成熟期/衰老期）
        开关OFF: 老版本 — 简单 MA5 断线止盈

        参数:
            regime_mult: 大盘环境跟踪止损乘数（由 market_regime 决定）
        """
        if state.cost_price <= 0 or state.highest_price <= 0:
            return False

        current_price = float(close.iloc[-1])
        profit_pct = (current_price - state.cost_price) / state.cost_price

        if profit_pct <= 0:
            return False

        if not self.enable_three_phase_trailing:
            ma5 = float(close.rolling(5).mean().iloc[-1]) if len(close) >= 5 else current_price
            return current_price < ma5

        drawdown = (state.highest_price - current_price) / state.highest_price

        # 计算 ATR（用于成熟期和衰老期）
        atr = None
        if len(close) >= CHANDELIER_LOOKBACK:
            atr_series = calc_atr(close, high, low, n=14)
            atr = float(atr_series.iloc[-1])

        # ---- 成长期（0-8%）：MA5断线保本优先 ----
        if profit_pct < PHASE_GROWTH:
            ma5 = float(close.rolling(5).mean().iloc[-1])
            if current_price < ma5:
                return True
            return False

        # ---- 成熟期（8-25%）：ATR自适应回撤 ----
        if profit_pct < PHASE_MATURE:
            if atr is not None:
                dd_threshold = self._calc_dynamic_drawdown_threshold(
                    state.highest_price, atr)
            else:
                dd_threshold = TRAILING_DRAWDOWN_FLOOR
            dd_threshold = dd_threshold * regime_mult
            if drawdown >= dd_threshold:
                return True
            return False

        # ---- 衰老期（>25%）：吊灯止损 + 宽松回撤 ----
        if atr is not None:
            chandelier_level = state.highest_price - CHANDELIER_ATR_MULTIPLE * atr * regime_mult
            if current_price <= chandelier_level:
                return True
        # 宽松回撤兜底
        if atr is not None:
            dd_threshold = self._calc_dynamic_drawdown_threshold(
                state.highest_price, atr)
        else:
            dd_threshold = TRAILING_DRAWDOWN_FLOOR
        dd_threshold = dd_threshold * regime_mult
        high_profit_dd = min(dd_threshold * PHASE_DECAY_DRAWDOWN_MULT, TRAILING_DRAWDOWN_CAP)
        return drawdown >= high_profit_dd

    # ================================================================
    #  全层诊断（只读，不修改状态）
    # ================================================================

    def diagnose_position(self, code, df, cost_price, current_price, highest_price):
        """对单只持仓进行五层信号全诊断（只读操作，不修改状态）。

        参数:
            code: 股票代码
            df: DataFrame 行情数据
            cost_price: 持仓成本价
            current_price: 当前价
            highest_price: 持仓期间最高价

        返回:
            dict: {
                'code', 'status', 'cost_price', 'current_price',
                'profit_pct', 'highest_price', 'current_layer',
                'layers': {
                    'bottom_line': {name: {'triggered': bool, 'value': str}},
                    'warning': {name: {'triggered': bool, 'value': str}},
                    'confirm': {...},
                    'clear': {...},
                    'trailing': {'移动止盈': {'triggered': bool, 'detail': str}}
                }
            }
        """
        state = self._get_state(code)
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        open_ = df['open'].astype(float)
        volume = df['volume'].astype(float)

        profit_pct = (current_price - cost_price) / cost_price * 100 if cost_price > 0 else 0.0

        # 状态文字
        if state is None:
            status = '持有中'
        elif state.cleared:
            status = '已清仓(%s)' % state.cleared_date
        elif state.confirm_reduced:
            status = '确认层减仓'
        elif state.warning_reduced:
            status = '预警层减仓'
        else:
            status = '持有中'

        # 当前层次
        if state and state.cleared:
            current_layer = '清仓层'
        elif state and state.confirm_reduced:
            current_layer = '确认层'
        elif state and state.warning_reduced:
            current_layer = '预警层'
        else:
            current_layer = '正常'

        layers = {
            'bottom_line': {},
            'warning': {},
            'confirm': {},
            'clear': {},
            'trailing': {},
        }

        # ---- 底线层 ----
        if len(close) >= 2 and cost_price > 0:
            curr = float(close.iloc[-1])
            loss_pct = (curr - cost_price) / cost_price * 100
            effective_stop = state.hard_stop_loss if state and state.hard_stop_loss is not None else self.hard_stop_loss
            layers['bottom_line']['累积亏损'] = {
                'triggered': loss_pct <= effective_stop * 100,
                'value': '%.1f%%' % loss_pct,
            }
            prev_close = float(close.iloc[-2])
            if prev_close > 0:
                daily_drop = (curr - prev_close) / prev_close * 100
                layers['bottom_line']['单日跌幅'] = {
                    'triggered': daily_drop <= BOTTOM_LINE_DAILY_DROP_PCT * 100,
                    'value': '%.1f%%' % daily_drop,
                }
        else:
            layers['bottom_line']['累积亏损'] = {'triggered': False, 'value': '--'}
            layers['bottom_line']['单日跌幅'] = {'triggered': False, 'value': '--'}

        # ---- 预警层 ----
        # B1: 爆量分歧
        b1_t = False
        b1_ratio = ''
        if len(volume) >= 6 and len(close) >= 6:
            v5 = volume.rolling(5).mean()
            cv = float(volume.iloc[-1])
            av = float(v5.iloc[-1])
            if av > 0:
                ratio = cv / av
                if ratio >= VOLUME_RATIO_THRESHOLD:
                    sh = detect_long_upper_shadow(high, close, open_)
                    if sh.iloc[-1]:
                        b1_t = True
                b1_ratio = '%.1fx' % ratio
        layers['warning']['B1爆量'] = {'triggered': b1_t, 'value': b1_ratio}

        # B2: 量价背离
        b2_t, b2_r = detect_volume_price_divergence(close, volume)
        b2_val = ''
        if b2_r:
            b2_val = '%.1fx' % b2_r
        layers['warning']['B2背离'] = {'triggered': b2_t, 'value': b2_val}

        # C2: MACD红柱缩短
        c2_t = self._signal_macd_shortening(close)
        layers['warning']['C2缩短'] = {'triggered': c2_t, 'value': ''}

        # KDJ死叉
        kdj_t = self._signal_kdj_death(close, high, low)
        layers['warning']['KDJ死叉'] = {'triggered': kdj_t, 'value': ''}

        # ---- 确认层 ----
        ma10 = close.rolling(10).mean()
        a2_t = self._signal_break_ma10(close, ma10)
        a2_val = ''
        if a2_t and len(close) >= 11:
            a2_val = '%.1f%%' % ((float(ma10.iloc[-1]) - float(close.iloc[-1])) / float(ma10.iloc[-1]) * 100)
        layers['confirm']['A2破10日'] = {'triggered': a2_t, 'value': a2_val}

        c1_t = self._signal_high_long_shadow(high, close, open_)
        layers['confirm']['C1上影'] = {'triggered': c1_t, 'value': ''}

        b3_t = self._signal_high_volume_negative(close, open_, volume)
        layers['confirm']['B3天量'] = {'triggered': b3_t, 'value': ''}

        # ---- 清仓层 ----
        ma20 = close.rolling(20).mean()
        a3_t = self._signal_break_ma20_3days(close, ma20)
        layers['clear']['A3破20日'] = {'triggered': a3_t, 'value': ''}

        c3_t = self._signal_break_highest_low(close, high, low)
        layers['clear']['C3破低'] = {'triggered': c3_t, 'value': ''}

        # ---- 移动止盈（P2-1 三阶段版）----
        trailing_t = False
        trailing_detail = ''

        if cost_price > 0 and highest_price > 0:
            profit_r = (current_price - cost_price) / cost_price
            drawdown_pct = (highest_price - current_price) / highest_price * 100
            profit_pct_val = profit_r * 100

            if profit_pct_val > 0:
                atr = None
                if len(close) >= CHANDELIER_LOOKBACK:
                    atr_series = calc_atr(close, high, low, n=14)
                    atr = float(atr_series.iloc[-1])

                if profit_pct_val < PHASE_GROWTH * 100:
                    # 成长期：MA5断线
                    ma5_v = float(close.rolling(5).mean().iloc[-1]) if len(close) >= 5 else 0
                    below_ma5 = current_price < ma5_v
                    trailing_detail = '成长期%+.1f%%<%d%%, %s' % (
                        profit_pct_val, int(PHASE_GROWTH * 100),
                        '已破MA5' if below_ma5 else '未破MA5')
                    trailing_t = below_ma5
                elif profit_pct_val < PHASE_MATURE * 100:
                    # 成熟期：ATR自适应回撤
                    if atr is not None:
                        dd_threshold = self._calc_dynamic_drawdown_threshold(
                            highest_price, atr) * 100
                    else:
                        dd_threshold = TRAILING_DRAWDOWN_FLOOR * 100
                    trailing_t = drawdown_pct >= dd_threshold
                    trailing_detail = '成熟期%+.1f%%, 回撤%.1f%%, 阈值%.1f%%' % (
                        profit_pct_val, drawdown_pct, dd_threshold)
                else:
                    # 衰老期：吊灯止损+宽松回撤
                    chandelier_t = (atr is not None and
                                    current_price <= highest_price - CHANDELIER_ATR_MULTIPLE * atr)
                    if atr is not None:
                        dd_threshold = self._calc_dynamic_drawdown_threshold(
                            highest_price, atr) * 100
                    else:
                        dd_threshold = TRAILING_DRAWDOWN_FLOOR * 100
                    high_profit_dd = min(dd_threshold * PHASE_DECAY_DRAWDOWN_MULT, TRAILING_DRAWDOWN_CAP * 100)
                    trailing_t = chandelier_t or (drawdown_pct >= high_profit_dd)
                    trailing_detail = '衰老期%+.1f%%, 吊灯=%s, 回撤%.1f%%, 阈值%.1f%%' % (
                        profit_pct_val, '触发' if chandelier_t else '未触发',
                        drawdown_pct, high_profit_dd)

        layers['trailing']['移动止盈'] = {
            'triggered': trailing_t,
            'detail': trailing_detail,
        }

        return {
            'code': code,
            'status': status,
            'cost_price': cost_price,
            'current_price': current_price,
            'profit_pct': profit_pct,
            'highest_price': highest_price,
            'current_layer': current_layer,
            'layers': layers,
        }

    # ================================================================
    #  信号检测函数
    # ================================================================

    def _signal_break_ma5(self, close):
        """A1: 收盘价跌破 MA5"""
        if len(close) < 6:
            return False
        ma5 = close.rolling(5).mean()
        return bool(close.iloc[-1] < ma5.iloc[-1])

    def _signal_break_ma10(self, close, ma10):
        """A2: 收盘价跌破 MA10"""
        if len(close) < 11:
            return False
        return bool(close.iloc[-1] < ma10.iloc[-1])

    def _signal_break_ma20_3days(self, close, ma20):
        """A3: 跌破 MA20 且 3 日未收复"""
        if len(close) < 24:
            return False
        if close.iloc[-1] >= ma20.iloc[-1]:
            return False
        days_below = 0
        for i in range(min(CLEAR_MA20_DAYS, len(close) - 1)):
            if close.iloc[-1 - i] < ma20.iloc[-1 - i]:
                days_below += 1
            else:
                break
        return days_below >= CLEAR_MA20_DAYS

    def _signal_explosive_volume(self, close, high, open_, volume):
        """
        B1: 爆量分歧
        - 成交量 > 均量5 × 1.5
        - 长上影线
        """
        if len(volume) < 6 or len(close) < 6:
            return False, ""

        vol_ma5 = volume.rolling(5).mean()
        current_vol = float(volume.iloc[-1])
        avg_vol = float(vol_ma5.iloc[-1])

        if avg_vol <= 0:
            return False, ""

        vol_ratio = current_vol / avg_vol
        if vol_ratio < VOLUME_RATIO_THRESHOLD:
            return False, ""

        has_long_shadow = detect_long_upper_shadow(high, close, open_)
        if not has_long_shadow.iloc[-1]:
            return False, ""

        return True, "B1:爆量分歧(%.1f倍)" % vol_ratio

    def _signal_b1_nextday_unrecovered(self, close, open_, state):
        """B1 隔日检查：次日不修复 → 追加减仓 20%"""
        if len(close) < 2:
            return False

        current_price = float(close.iloc[-1])
        ma5 = float(close.rolling(5).mean().iloc[-1])

        if current_price > ma5 and current_price > float(open_.iloc[-1]):
            state.b1_needs_nextday_check = False
            state.b1_additional_reduced = False
            return False

        return True

    def _signal_volume_divergence(self, close, volume):
        """B2: 量价背离"""
        diverged, _ = detect_volume_price_divergence(close, volume)
        return diverged

    def _signal_macd_shortening(self, close):
        """C2: MACD 红柱连续缩短 3 日"""
        if len(close) < MACD_SHORTEN_DAYS + 26:
            return False

        _, _, macd_bar = self._calc_macd_safe(close)

        if len(macd_bar) < MACD_SHORTEN_DAYS + 1:
            return False

        for i in range(MACD_SHORTEN_DAYS + 1):
            if pd.isna(macd_bar.iloc[-1 - i]):
                return False

        if macd_bar.iloc[-1] <= 0:
            return False

        for i in range(MACD_SHORTEN_DAYS):
            if macd_bar.iloc[-1 - i] >= macd_bar.iloc[-2 - i]:
                return False

        return True

    def _signal_kdj_death(self, close, high, low):
        """5日线斜率走平 + KDJ 死叉"""
        if len(close) < 15:
            return False

        ma5 = close.rolling(5).mean()
        if len(ma5) < 3:
            return False
        angle = calc_angle_simple(ma5)
        if angle is None or abs(angle) > MA5_SLOPE_FLAT_DEG:
            return False

        k, d, j = calc_kdj(close, high, low)
        if len(k) < 3 or len(d) < 3:
            return False
        if pd.isna(k.iloc[-1]) or pd.isna(d.iloc[-1]):
            return False
        if pd.isna(k.iloc[-2]) or pd.isna(d.iloc[-2]):
            return False

        return bool(k.iloc[-1] < d.iloc[-1] and k.iloc[-2] >= d.iloc[-2])

    def _signal_high_long_shadow(self, high, close, open_):
        """C1: 高位长上影线"""
        if len(close) < 10:
            return False

        recent_high = float(close.iloc[-5:].max())
        compare_price = float(close.iloc[-10])
        if compare_price <= 0:
            return False
        price_increase = (recent_high - compare_price) / compare_price
        if price_increase < 0.05:
            return False

        shadow = detect_long_upper_shadow(high, close, open_)
        return bool(shadow.iloc[-1])

    def _signal_high_volume_negative(self, close, open_, volume):
        """B3: 高位天量收阴"""
        if len(close) < 10:
            return False

        if len(close) >= 20:
            recent_max = float(close.iloc[-5:].max())
            period_max = float(close.iloc[-20:].max())
            if recent_max < period_max * 0.95:
                return False

        if close.iloc[-1] >= open_.iloc[-1]:
            return False

        if len(volume) >= 6:
            vol_ma5 = volume.rolling(5).mean()
            if float(volume.iloc[-1]) < float(vol_ma5.iloc[-1]) * VOLUME_RATIO_THRESHOLD:
                return False

        return True

    def _signal_break_highest_low(self, close, high, low):
        """C3: 跌破最高价当日最低点"""
        if len(high) < 30:
            return False

        recent_high = high.iloc[-30:]
        highest_val = recent_high.max()
        highest_pos = 0
        for i in range(len(recent_high)):
            if recent_high.iloc[i] >= highest_val:
                highest_pos = i
                break

        lowest_of_highest_day = float(low.iloc[-30:].iloc[highest_pos])
        current_price = float(close.iloc[-1])
        return current_price < lowest_of_highest_day

    # ================================================================
    #  辅助方法
    # ================================================================

    def _calc_macd_safe(self, close):
        """安全计算 MACD，处理 NaN。"""
        if len(close) < 26:
            return None, None, None
        try:
            ema12 = close.ewm(span=12, adjust=False).mean()
            ema26 = close.ewm(span=26, adjust=False).mean()
            diff = ema12 - ema26
            dea = diff.ewm(span=9, adjust=False).mean()
            macd = 2 * (diff - dea)
            return diff, dea, macd
        except Exception:
            return None, None, None


# ============================================================
#  方案B诊断格式化输出
# ============================================================

def format_plan_b_diagnosis(diagnosis_list, today_str, now_str=''):
    """将 diagnose_position() 返回的诊断列表格式化为方案B输出。

    参数:
        diagnosis_list: list of dict (diagnose_position 返回值)
        today_str: 日期字符串 (YYYYMMDD)
        now_str: 时间字符串 (HHMM)

    返回:
        list of str: 格式化后的文本行
    """
    lines = []
    lines.append('=' * 70)
    lines.append('[风控专岗] 持仓风控明细 - %s %s' % (today_str, now_str))
    lines.append('')

    # 分类计数
    cnt_normal = 0
    cnt_warning = 0
    cnt_confirm = 0
    cnt_clear = 0

    for diag in diagnosis_list:
        code = diag['code']
        status = diag['status']
        cost = diag['cost_price']
        curr = diag['current_price']
        profit = diag['profit_pct']
        highest = diag['highest_price']

        # 统计
        layer = diag['current_layer']
        if layer == '正常':
            cnt_normal += 1
        elif layer == '预警层':
            cnt_warning += 1
        elif layer == '确认层':
            cnt_confirm += 1
        elif layer == '清仓层':
            cnt_clear += 1

        lines.append(' %s ( %s . 成本%.2f . 现价%.2f . 盈利%+.1f%% . 最高%.2f )' % (
            code, status, cost, curr, profit, highest))
        lines.append(' ' + '-' * 65)

        layers = diag['layers']

        def _sym(t):
            return '√' if t else '×'

        # ---- 底线层 ----
        bl_parts = []
        for name, info in layers['bottom_line'].items():
            if info['value'] and info['value'] != '--':
                bl_parts.append('%s: %s(%s)' % (name, _sym(info['triggered']), info['value']))
            else:
                bl_parts.append('%s: %s' % (name, _sym(info['triggered'])))
        if bl_parts:
            lines.append(' 底线层   ' + ' | '.join(bl_parts))

        # ---- 预警层 ----
        w_names = list(layers['warning'].keys())
        w_parts1 = []
        w_parts2 = []
        for name in w_names:
            info = layers['warning'][name]
            if info['value']:
                s = '%s: %s(%s)' % (name, _sym(info['triggered']), info['value'])
            else:
                s = '%s: %s' % (name, _sym(info['triggered']))
            if len(w_parts1) < 2:
                w_parts1.append(s)
            else:
                w_parts2.append(s)
        if w_parts1:
            lines.append(' 预警层   ' + ' | '.join(w_parts1))
        if w_parts2:
            lines.append('          ' + ' | '.join(w_parts2))

        # ---- 确认层 ----
        c_parts = []
        for name, info in layers['confirm'].items():
            if info['value']:
                c_parts.append('%s: %s(%s)' % (name, _sym(info['triggered']), info['value']))
            else:
                c_parts.append('%s: %s' % (name, _sym(info['triggered'])))
        if c_parts:
            lines.append(' 确认层   ' + ' | '.join(c_parts))

        # ---- 清仓层 ----
        cl_parts = []
        for name, info in layers['clear'].items():
            if info['value']:
                cl_parts.append('%s: %s(%s)' % (name, _sym(info['triggered']), info['value']))
            else:
                cl_parts.append('%s: %s' % (name, _sym(info['triggered'])))
        if cl_parts:
            lines.append(' 清仓层   ' + ' | '.join(cl_parts))

        # ---- 移动止盈 ----
        t_info = layers['trailing']['移动止盈']
        if t_info.get('detail'):
            lines.append(' 移动止盈  %s  %s' % (_sym(t_info['triggered']), t_info['detail']))
        else:
            lines.append(' 移动止盈  %s' % _sym(t_info['triggered']))

    lines.append('=' * 70)
    total = len(diagnosis_list)
    lines.append(' 汇总: 持仓%d只 | 持有中%d | 预警%d | 确认%d | 清仓%d' % (
        total, cnt_normal, cnt_warning, cnt_confirm, cnt_clear))

    return lines

# ====== core/position_sizer.py ======
"""仓位计算 — 凯利公式"""


# ============================================================
#  原始骨架函数保留
# ============================================================

def kelly_criterion(win_rate, avg_win, avg_loss):
    """凯利公式: f* = (p*b - q)/b，保守版减半，上限20%"""
    if avg_loss <= 0 or avg_win <= 0:
        return 0.0
    if win_rate <= 0 or win_rate >= 1:
        return 0.0
    b = avg_win / avg_loss
    q = 1 - win_rate
    f = (win_rate * b - q) / b
    if f <= 0:
        return 0.0
    conservative = f / 2
    return min(conservative, 0.20)


def get_position_by_kelly(available_cash, stock_price, strategy_stats):
    """根据凯利公式算股数"""
    if stock_price <= 0 or available_cash <= 0:
        return 0
    win_rate = strategy_stats.get('win_rate', 0.5)
    avg_win = strategy_stats.get('avg_win', 0.05)
    avg_loss = strategy_stats.get('avg_loss', 0.03)
    kelly_pct = kelly_criterion(win_rate, avg_win, avg_loss)
    amount = available_cash * kelly_pct
    shares = int(amount / stock_price / 100) * 100
    return max(shares, 0)

# ====== adapters/exit_adapters/base.py ======
from abc import ABC, abstractmethod
from enum import Enum


class LogicStatus(Enum):
    STRONG = "STRONG"   # 买入逻辑还在，正常持有
    WEAK = "WEAK"       # 逻辑减弱，跌破保护线则止盈
    GONE = "GONE"       # 逻辑完全消失，直接止盈


class ExitAction(Enum):
    HOLD = "HOLD"
    REDUCE = "REDUCE"   # 减仓50%
    SELL = "SELL"       # 清仓


class ExitDecision(object):
    def __init__(self, action, reason, pct=1.0):
        # type: (ExitAction, str, float) -> None
        self.action = action
        self.reason = reason
        self.pct = pct


class StrategyExitAdapter(ABC):
    """策略侧止盈适配层基类"""
    
    def calc_protect_line(self, buy_price, max_profit):
        # type: (float, float) -> float
        """
        默认利润保护线计算器（各策略可覆盖）
        max_profit: 买入至今最高浮盈比例 0.xx
        """
        if max_profit < 0.05:
            return buy_price * 0.92  # <5%浮盈：引擎-8%兜底
        elif max_profit < 0.15:
            return buy_price        # 5%-15%：保本线
        elif max_profit < 0.30:
            return buy_price * (1 + max_profit * 0.5)  # 15%-30%：锁50%利润
        else:
            return buy_price * (1 + max_profit * 0.8)  # >30%：锁80%利润
    
    @abstractmethod
    def get_logic_status(self, code, today_data):
        # type: (str, dict) -> LogicStatus
        """判断当前买入逻辑状态"""
        pass
    
    def check_strategy_exit(self, code, today_data, holdings_state):
        # type: (str, dict, dict) -> ExitDecision
        """
        主入口：策略侧止盈判断
        holdings_state 必须包含：
          - buy_price: 买入成本
          - max_profit_since_buy: 买入至今最高浮盈比例
          - current_price: 当前价
        """
        logic_status = self.get_logic_status(code, today_data)
        
        # 逻辑完全消失 → 直接清仓
        if logic_status == LogicStatus.GONE:
            return ExitDecision(ExitAction.SELL, "买入逻辑消失", 1.0)
        
        protect_line = self.calc_protect_line(
            holdings_state[code]["buy_price"],
            holdings_state[code]["max_profit_since_buy"]
        )
        
        current_price = holdings_state[code]["current_price"]
        
        # 双重触发：逻辑减弱 AND 跌破保护线 → 清仓
        if logic_status == LogicStatus.WEAK and current_price < protect_line:
            return ExitDecision(ExitAction.SELL, "逻辑减弱+跌破保护线", 1.0)
        
        # 逻辑减弱但未破保护线 → 减仓50%（提前锁定利润）
        if logic_status == LogicStatus.WEAK:
            return ExitDecision(ExitAction.REDUCE, "趋势减弱+提前减仓", 0.5)
        
        # 逻辑还在 → 持有
        return ExitDecision(ExitAction.HOLD, "买入逻辑仍在", 0.0)

# ====== adapters/exit_adapters/trend_62.py ======
"""
Trend62ExitAdapter - 趋势型6+2止盈适配器

4个趋势减弱信号（满足任意2个算WEAK）：
1. 连涨>=2日后首阴（close<open）
2. 今日量比<0.85（缩量）
3. 量价背离（价涨量缩）
4. 趋势走弱（MA5下穿MA10 或 收盘跌破MA20）
"""


class Trend62ExitAdapter(StrategyExitAdapter):
    """趋势型止盈适配器 - 6+2评分策略"""

    def _calc_consecutive_up_days(self, df, today_idx):
        # type: (object, int) -> int
        """计算今日之前连续上涨天数"""
        if today_idx < 1:
            return 0
        count = 0
        for i in range(today_idx - 1, -1, -1):
            c = float(df['close'].iloc[i])
            o = float(df['open'].iloc[i])
            if c > o:
                count += 1
            else:
                break
        return count

    def _calc_volume_ratio(self, df, today_idx):
        # type: (object, int) -> float
        """今日量比 = 今日成交量 / 前5日均量"""
        if today_idx < 5:
            return 1.0
        vol_ma5 = 0.0
        for i in range(today_idx - 5, today_idx):
            vol_ma5 += float(df['volume'].iloc[i])
        vol_ma5 = vol_ma5 / 5.0
        today_vol = float(df['volume'].iloc[today_idx])
        if vol_ma5 <= 0:
            return 1.0
        return today_vol / vol_ma5

    def _check_price_volume_divergence(self, df, today_idx):
        # type: (object, int) -> bool
        """量价背离：今日价格创新高但成交量萎缩"""
        if today_idx < 20:
            return False
        today_close = float(df['close'].iloc[today_idx])
        today_vol = float(df['volume'].iloc[today_idx])
        prev_high = 0.0
        prev_vol_avg = 0.0
        for i in range(max(0, today_idx - 20), today_idx):
            h = float(df['close'].iloc[i])
            if h > prev_high:
                prev_high = h
            prev_vol_avg += float(df['volume'].iloc[i])
        prev_vol_avg = prev_vol_avg / min(20, today_idx)
        if prev_vol_avg <= 0:
            return False
        return today_close > prev_high and today_vol < prev_vol_avg * 0.7

    def _check_trend_weakening(self, df, today_idx):
        # type: (object, int) -> bool
        """趋势走弱：MA5下穿MA10 或 收盘跌破MA20"""
        if today_idx < 20:
            return False

        today_close = float(df['close'].iloc[today_idx])

        # MA20
        ma20 = 0.0
        for i in range(today_idx - 19, today_idx + 1):
            ma20 += float(df['close'].iloc[i])
        ma20 = ma20 / 20.0

        if today_close < ma20:
            return True

        # MA5下穿MA10
        ma5_now = 0.0
        ma10_now = 0.0
        for i in range(today_idx - 4, today_idx + 1):
            ma5_now += float(df['close'].iloc[i])
        ma5_now = ma5_now / 5.0
        for i in range(today_idx - 9, today_idx + 1):
            ma10_now += float(df['close'].iloc[i])
        ma10_now = ma10_now / 10.0

        ma5_prev = 0.0
        ma10_prev = 0.0
        for i in range(today_idx - 5, today_idx):
            ma5_prev += float(df['close'].iloc[i])
        ma5_prev = ma5_prev / 5.0
        for i in range(today_idx - 10, today_idx):
            ma10_prev += float(df['close'].iloc[i])
        ma10_prev = ma10_prev / 10.0

        if ma5_prev >= ma10_prev and ma5_now < ma10_now:
            return True

        return False

    def get_logic_status(self, code, today_data):
        # type: (str, dict) -> LogicStatus
        """判断买入逻辑状态"""
        weak_signals = 0

        if today_data is None or len(today_data) < 20:
            return LogicStatus.STRONG

        today_idx = len(today_data) - 1

        # 信号1：连涨>=3日后首阴（close<open）
        consecutive_up = self._calc_consecutive_up_days(today_data, today_idx)
        today_close = float(today_data['close'].iloc[today_idx])
        today_open = float(today_data['open'].iloc[today_idx])
        if consecutive_up >= 3 and today_close < today_open:
            weak_signals += 1

        # 信号2：缩量（量比<0.6）
        volume_ratio = self._calc_volume_ratio(today_data, today_idx)
        if volume_ratio < 0.6:
            weak_signals += 1

        # 信号3：量价背离
        if self._check_price_volume_divergence(today_data, today_idx):
            weak_signals += 1

        # 信号4：趋势走弱（MA5下穿MA10 或 收盘跌破MA20）
        if self._check_trend_weakening(today_data, today_idx):
            weak_signals += 1

        if weak_signals >= 2:
            return LogicStatus.WEAK
        return LogicStatus.STRONG

