def _lightweight_yaml_parse(text):
    """轻量 YAML 解析，仅支持本项目 global_config.yaml 的简单格式。

    支持：顶层 section、key: value、bool、数字、字符串路径。
    """
    result = {}
    current_section = None
    for raw_line in text.splitlines():
        line = raw_line.strip()
        if not line or line.startswith('#'):
            continue
        if ':' not in line:
            continue
        key, _, value = line.partition(':')
        key = key.rstrip()
        value = value.strip()
        if not value:
            current_section = key
            result.setdefault(current_section, {})
            continue
        val = value.strip('"').strip("'")
        if val.lower() in ('true', 'yes'):
            parsed = True
        elif val.lower() in ('false', 'no'):
            parsed = False
        else:
            try:
                parsed = int(val)
            except ValueError:
                try:
                    parsed = float(val)
                except ValueError:
                    parsed = val
        if current_section is not None:
            result[current_section][key] = parsed
        else:
            result[key] = parsed
    return result


def _load_config():
    """加载 config。策略自包含：读不到 config 文件时用内置默认配置。
    候选路径按优先级尝试，都不存在则用 _DEFAULT_CONFIG（拿任何设备都能跑）。
    """
    candidates = [
        'D:/QMT_STRATEGIES/config/global_config.yaml',
        'config/global_config.yaml',
    ]
    config_path = None
    for cp in candidates:
        try:
            if os.path.exists(cp):
                config_path = cp
                break
        except Exception:
            continue
    if config_path is None:
        return dict(_DEFAULT_CONFIG)
    try:
        with open(config_path, encoding='utf-8') as f:
            text = f.read()
    except Exception:
        return dict(_DEFAULT_CONFIG)
    try:
        import yaml
        cfg = yaml.safe_load(text) or {}
    except ImportError:
        cfg = _lightweight_yaml_parse(text)
    except Exception:
        cfg = _lightweight_yaml_parse(text)
    if not cfg:
        cfg = dict(_DEFAULT_CONFIG)
    return cfg

